import { type PropsWithChildren, type ReactElement } from 'react';

import { SeriesItemValue } from './SeriesItemValue.js';
import type { TruncationMode } from '../../../../../../../typography/text-ellipsis/TextEllipsis.js';
import { DEFAULT_TRUNCATION_MODE } from '../../../../../constants.js';
import type { SeriesActionsTemplate } from '../../../../../types/series-actions-template.js';
import { ShapeIcon } from '../../../../shape/ShapeIcon.js';
import { type VariantShape } from '../../../../shape/type.js';
import { TooltipText } from '../../../section-components/atoms/TooltipText.js';
import { TooltipInfoContent } from '../../../section-components/TooltipInfoContent/TooltipInfoContent.js';
import { TooltipItem } from '../../../section-components/TooltipItem/TooltipItem.js';
import { TooltipSymbolContent } from '../../../section-components/TooltipSymbolContent/TooltipSymbolContent.js';

/** @internal */
export interface SeriesItemProps {
  color: string;
  name: string;
  value?: string | string[];
  variant?: VariantShape;
  actions?: () => SeriesActionsTemplate;
  defaultActions?: ReactElement<PropsWithChildren>;
  truncationMode?: TruncationMode;
}

/** @internal */
export const SeriesItem = (props: SeriesItemProps) => {
  const {
    color,
    name,
    value,
    variant = 'single',
    actions,
    defaultActions,
    truncationMode = DEFAULT_TRUNCATION_MODE,
  } = props;

  return (
    <TooltipItem actions={actions} defaultActions={defaultActions}>
      <TooltipSymbolContent>
        <ShapeIcon shape={variant} color={color} />
      </TooltipSymbolContent>
      <TooltipInfoContent>
        <TooltipText truncationMode={truncationMode}>{name}</TooltipText>
      </TooltipInfoContent>
      {!!value && (
        <SeriesItemValue truncationMode={truncationMode} value={value} />
      )}
    </TooltipItem>
  );
};

SeriesItem['displayName'] = 'ChartTooltip.SeriesItem';
